var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전 병력에 전파한다! 현 시간부로 지정된 포대로 이동해라!</color>","JPN":"<color=#ffd34c>全兵力に告ぐ！　現時刻より指定の砲台へ移動せよ！</color>","ENG":"<color=#ffd34c>Attention, all troops! Move out to your designated batteries immediately!</color>","TWN":"<color=#ffd34c>通知所有戰鬥人員！現在立即前往指定炮臺！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"전대장에게 잡아 먹히기 싫으면 꾸물대지 말고 움직여!","JPN":"戦隊長に喰われたくなければ、もたもたしないで動け！","ENG":"Get moving if you don't want the Commander to devour you!","TWN":"如果不想被隊長吃掉，就給我動作快點！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐야? 돌아오자마자 이건 또 무슨 난리야?","JPN":"何？　帰ってきたとたんに何の騒ぎなの？","ENG":"Huh? What's all the commotion about?","TWN":"什麼？剛回來又要做什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"방주의 봉인이 약해졌다.","JPN":"箱舟の封印が弱まった。","ENG":"The Ark's seal has grown weak.","TWN":"方舟的封印變弱了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"클리파 차원으로부터 점점 더 강력한 에너지가 쏟아져 들어오고 있어.","JPN":"クリファ次元から強力なエネルギーが流れ込んできている。","ENG":"The energy flowing in from the Qlipha dimension is growing more and more powerful.","TWN":"從逆卡巴拉湧出了更強的能量。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이 힘을 이용해서 싸우자고 한 건 네 의견이었을 텐데?","JPN":"この力を用いて戦おうと進言したのは貴様だろう？","ENG":"I thought it was your idea to use that power to fight?","TWN":"妳不是提議說，要利用這股力量戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"맞아. 하지만 이렇게 성급하게 굴 필요는 없잖아.","JPN":"ええ。でもそんなに急ぐことはないんじゃない？","ENG":"True. But there's no need to rush like this.","TWN":"沒錯，但沒必要這麼急躁。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"충분한 힘을 얻으려면 시간이 필요해.","JPN":"十分な力を得るには時間が必要よ。","ENG":"We'll need more time to get enough power.","TWN":"要獲得充分的力量需要時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"굳이 싸워서 애들을 쓸데없이 희생시키지 않아도 된다고.","JPN":"無駄に戦って、子どもたちに余計な犠牲を強いることはないわ。","ENG":"We don't need to fight so quickly and sacrifice the troops for no reason.","TWN":"沒必要硬拼，讓孩子們白白犧牲。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"왜? 네가 잡아먹을 먹이가 줄어들어서 아쉽기라도 한가?","JPN":"貴様の獲物が減ってしまうのがそんなに残念か？","ENG":"Why not? Are you disappointed to lose prey you can feed on?","TWN":"怎麼？妳是怕妳的食物減少嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"무슨 소리야?","JPN":"何言ってるの？","ENG":"What are you talking about?","TWN":"妳在說什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"먹이라니, 난 그저......","JPN":"獲物だなんて、私はただ……","ENG":"Prey? I was just—","TWN":"什麼食物，我只是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네가 뒤에서 내 병력을 야금야금 갉아먹는 걸 내가 모를 줄 알았나?","JPN":"裏で私の兵力を少しずつ喰い荒らしていただろう。\\n私が気付いていないとでも思ったか？","ENG":"Did you think I wouldn't notice you nibbling away at my troops?","TWN":"妳以為我不知道妳背著我，一點一點地在吞噬我的兵力嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그러고 보니 발레리가 안 보이는군. 어디 두고 왔는지 궁금해지는데.","JPN":"そういえばヴァレリーの姿が見えないな。\\nどこかに置き去りにしたとも思えないが。","ENG":"Speaking of which, I do not see Valeriy here. I'm starting to wonder where you left him.","TWN":"我怎麼沒看到瓦萊里，真好奇妳把他弄去哪了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"......쳇. 사레들게 하네.","JPN":"……チッ。消化に悪いったらないわね。","ENG":"Tsk. You almost made me choke.","TWN":"……切，妳差點害我噎到。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그래. 내가 흡수했어.","JPN":"そうよ。私が吸収したわ。","ENG":"Yes. I absorbed him.","TWN":"沒錯，是我把他吸收了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"내버려 두면 죽을 텐데 그냥 버리는 것보단 낫잖아?","JPN":"だって放っておくと死んじゃうのよ。そのまま捨てちゃうより良いでしょう？","ENG":"He was going to die anyway. Waste not, want not.","TWN":"反正我不吃他也會死，不如讓我吃掉還比較好吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"흥. 뻔뻔스럽게 구는 걸 보니 그나마 좀 낫군.","JPN":"フン。そう図々しく振舞った方が幾分かマシだな。","ENG":"Hmpf! That's more like it, you being the shameless one that you are.","TWN":"哼，妳這厚顏無恥的模樣，倒讓人看得順眼了些。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"더 이상 너의 <color=#ffd34c>상냥한 부전대장 놀이</color>를 봐 주는 건 너무 역겨우니까 말이다.","JPN":"これ以上、貴様の<color=#ffd34c>優しい副戦隊長ごっこ</color>を\\n見せられてはたまらん。気色悪くて反吐が出そうだ。","ENG":"I was growing sick of seeing you <color=#ffd34c>play a benevolent deputy commander</color>.","TWN":"妳那<color=#ffd34c>善良的副隊長遊戲</color>已經夠讓人噁心了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"알겠어. 하지만 지금 무리해서 공격할 이유가 없는 건 사실이잖아?","JPN":"わかったわ。\\nでも、今無理して攻め込む理由がないのは事実でしょう？","ENG":"Point taken. But even so, there's no reason to stretch ourselves thin and attack right now, is there?","TWN":"知道了，但我們現在也沒有勉強攻擊的理由啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"아니. 그렇지 않아.","JPN":"そうでもないさ。","ENG":"Yes, there is.","TWN":"不，不對。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"<color=#ffd34c>사도</color>께서 계시를 내리셨다.","JPN":"<color=#ffd34c>使徒</color>が啓示をお下しになった。","ENG":"The <color=#ffd34c>Apostle</color> has sent a revelation.","TWN":"<color=#ffd34c>使徒</color>下達了啟示。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"뭐? 정말이야?","JPN":"えっ？　本当なの？","ENG":"What? For real?","TWN":"什麼？是真的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래. 그분께서 강림하실 시간이 얼마 남지 않았어.","JPN":"ああ。あの方が降臨なさる時も近い。","ENG":"Yes. Her advent is nigh.","TWN":"沒錯，它很快就會降臨了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"너도 그분의 심기를 거스르고 싶지는 않겠지?","JPN":"貴様とて、あの方の機嫌を損ねたくはないだろう？","ENG":"You wouldn't want to cross her, would you?","TWN":"妳應該不想違背它的意思吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......알았어. 알았다고. 하면 될 거 아냐.","JPN":"……わかった。わかったわよ。やればいいんでしょう？","ENG":"Okay, okay. I'll do as you say.","TWN":"……知道了，知道了。我會照妳說的去做。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"쓸데없는 이유를 갖다 붙이기는...... 노리는 건 결국 그 바퀴벌레면서.","JPN":"余計な理由付けなんかして……\\nどうせ狙いはあのゴキブリでしょうに。","ENG":"Why does she bother coming up with excuses like that? I know she's only really after the Roach.","TWN":"還編那邊多理由……結果還不是想對付那隻蟑螂。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"침식체 주제에 뭐 저리 쓸데없는 거에 집착하는 거람?","JPN":"侵食体のくせして、どうして余計なことにばかりこだわるのかしら？","ENG":"What's a C.O. doing obsessing over some crap?","TWN":"區區一個侵蝕體，執著那些沒用的東西幹嘛？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};